#include <stdio.h>
#include <stdlib.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, K;
        scanf("%d %d", &N, &K);
        int* T = (int*)malloc(N * sizeof(int));
        for (int i = 0; i < N; i++) {
            scanf("%d", &T[i]);
        }
        int minTime = -1;
        for (int i = 0; i < N; i++) {
            for (int j = i + 1; j < N; j++) {
                if (T[i] + T[j] == K && T[i] != T[j]) {
                    int time = (i + 1) > (N - j) ? (i + 1) : (N - j);
                    if (minTime == -1 || time < minTime) {
                        minTime = time;
                    }
                }
            }
        }
        printf("%d\n", minTime);
    }
    return 0;
}

